-- Ken's Hardened V2 Fix

local b64_0xIIlI11 = {}
local char_0xlllIlI='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xIlll1I=1,#char_0xlllIlI do b64_0xIIlI11[char_0xlllIlI:sub(i_0xIlll1I,i_0xIlll1I)] = i_0xIlll1I - 1 end

function b64_0xIIlI11.dec_0xIlIIlI(d_0xlIllll)
    d_0xlIllll = string.gsub(d_0xlIllll, '[^'..char_0xlllIlI..'=]', '')
    local r_0xlII111 = {}
    for i_0xIlll1I=1, #d_0xlIllll, 4 do
        local c_0x1IIlll = b64_0xIIlI11[d_0xlIllll:sub(i_0xIlll1I,i_0xIlll1I)] or 0
        local c_0xl1lII1 = b64_0xIIlI11[d_0xlIllll:sub(i_0xIlll1I+1,i_0xIlll1I+1)] or 0
        local c_0xIlIlll, c_0x1IlIll = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xlIllll:sub(i_0xIlll1I+2,i_0xIlll1I+2)
        if ch3 == "=" then has3 = false else c_0xIlIlll = b64_0xIIlI11[ch3] or 0 end
        local ch4 = d_0xlIllll:sub(i_0xIlll1I+3,i_0xIlll1I+3)
        if ch4 == "=" then has4 = false else c_0x1IlIll = b64_0xIIlI11[ch4] or 0 end
        local b_0xllI1Il = c_0x1IIlll * (2^18) + c_0xl1lII1 * (2^12) + c_0xIlIlll * (2^6) + c_0x1IlIll
        local b_0xIl1IlI = math.floor(b_0xllI1Il / (2^16)) % (2^8)
        local b_0xIIlII1 = math.floor(b_0xllI1Il / (2^8)) % (2^8)
        local b_0xIllIIl = b_0xllI1Il % (2^8)
        table.insert(r_0xlII111, string.char(b_0xIl1IlI))
        if has3 then table.insert(r_0xlII111, string.char(b_0xIIlII1)) end
        if has4 then table.insert(r_0xlII111, string.char(b_0xIllIIl)) end
    end
    return table.concat(r_0xlII111)
end


local function bxor_0xIllI1I(a_0x1IIl1l,b_0xI1Il1I)
    if bit32 then return bit32.bxor(a_0x1IIl1l,b_0xI1Il1I) end
    local r_0xIlIlIl = 0
    for i_0xlllIlI = 0, 7 do
        local x_0xIllIll = a_0x1IIl1l % 2
        local y_0xI1llll = b_0xI1Il1I % 2
        if x_0xIllIll ~= y_0xI1llll then r_0xIlIlIl = r_0xIlIlIl + (2^i_0xlllIlI) end
        a_0x1IIl1l = math.floor(a_0x1IIl1l / 2)
        b_0xI1Il1I = math.floor(b_0xI1Il1I / 2)
    end
    return r_0xIlIlIl
end


local function bxor_str_0xl1l1II(s_0x1IIlII, k_0x11IlII)
    local r_0xllIlIl = {}
    for i_0xIIIIll=1, #s_0x1IIlII do
        local b_0xI1I1Il = string.byte(s_0x1IIlII, i_0xIIIIll)
        local kb_0x1I1llI = string.byte(k_0x11IlII, (i_0xIIIIll-1) % #k_0x11IlII + 1)
        r_0xllIlIl[i_0xIIIIll] = string.char(bxor_0xIllI1I(b_0xI1I1Il, kb_0x1I1llI))
    end
    return table.concat(r_0xllIlIl)
end


local function getkeys_0x1lIllI()
    local seed = b64_0xIIlI11.dec_0xIlIIlI("SFVMeFptdGE=")
    local k1_enc = b64_0xIIlI11.dec_0xIlIIlI("PGchNR4ORjA=")
    local k2_enc = b64_0xIIlI11.dec_0xIlIIlI("eRkFLRM0Ny4=")
    return bxor_str_0xl1l1II(k1_enc, seed), bxor_str_0xl1l1II(k2_enc, seed)
end


local function cff_0x1III1l(a_0xllllII)
    local st_0xIlIlll = 0
    local res_0xIllIlI = a_0xllllII
    while true do
        if st_0xIlIlll == 0 then
            res_0xIllIlI = res_0xIllIlI + 1
            st_0xIlIlll = 1
        elseif st_0xIlIlll == 1 then
            res_0xIllIlI = res_0xIllIlI * 2
            st_0xIlIlll = 2
        elseif st_0xIlIlll == 2 then
            res_0xIllIlI = res_0xIllIlI - 3
            st_0xIlIlll = 3
        else
            break
        end
    end
    return res_0xIllIlI
end


local function chain_0xIlIlIl(x) return x*2 end
local function chain_0x11l1Il(x) return chain_0xIlIlIl(x)+1 end


local d_0xI1Il1I = {
  {op=255, val="", is_enc=true},
}
local pc_0x1lI1Il = 1
local stk_0xIIIIII = {}
stk_0xIIIIII._jmp = nil


local disp_0xlllllI = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0x1lIllI()

local state_0xIlIlIl = 0
while true do
    if state_0xIlIlIl == 0 then  -- FETCH
        if pc_0x1lI1Il > #d_0xI1Il1I then break end
        local inst = d_0xI1Il1I[pc_0x1lI1Il]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xIIlI11.dec_0xIlIIlI(val)
            d = bxor_str_0xl1l1II(d, k2)
            val = bxor_str_0xl1l1II(d, k1)
        end
        stk_0xIIIIII._jmp = nil
        pc_0x1lI1Il = pc_0x1lI1Il + 1
        cur_op_0xI1I1Il = opcode
        cur_val_0xl1llll = val
        state_0xIlIlIl = 1

    elseif state_0xIlIlIl == 1 then  -- EXECUTE
        local handler = disp_0xlllllI[cur_op_0xI1I1Il]
        if handler then
            handler(stk_0xIIIIII, cur_val_0xl1llll)
        end
        if stk_0xIIIIII._jmp then
            pc_0x1lI1Il = pc_0x1lI1Il + stk_0xIIIIII._jmp
        end
        state_0xIlIlIl = 0
